    #[test]
    fn test_paragraph_splitting() {
        let chunker = FallbackChunker::new(10); // ~40 chars max
        let source = "Paragraph one content here.\n\nParagraph two content here.\n\nParagraph three.";
        let chunks = chunker.chunk(source, &meta()).unwrap();
        assert!(chunks.len() >= 2, "should split on paragraph boundaries, got {}", chunks.len());
        // Each chunk should fit within budget
        for c in &chunks {
            let estimate = c.content.len() / 4;
            assert!(estimate <= 10 || c.content.len() <= 40,
                "chunk too large: {} chars", c.content.len());
        }
    }

    #[test]
    fn test_line_splitting_fallback() {
        let chunker = FallbackChunker::new(5); // ~20 chars max
        // No paragraph breaks — falls back to line splitting
        let source = "line one here\nline two here\nline three here\nline four here";
        let chunks = chunker.chunk(source, &meta()).unwrap();
        assert!(chunks.len() >= 2, "should split on line boundaries");
    }

